-- KORYXA FORMATION — STATISTIQUES & DATA SCIENCE AVEC PYTHON — CHANTIER 4
-- Quiz par module, test final et projet final. Contenus non publiés.

ALTER TABLE public.quiz_questions
ADD COLUMN IF NOT EXISTS question_type TEXT NOT NULL DEFAULT 'qcm'
CHECK (question_type IN ('qcm','true_false','comprehension','mini_challenge')),
ADD COLUMN IF NOT EXISTS is_final_test BOOLEAN NOT NULL DEFAULT FALSE;

WITH target_module AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='statistics-data-science-python' AND m.order_index=0), seed(order_index,question_type,question,options,answer,difficulty,skill,explanation) AS (VALUES (1,'qcm','Quelle distinction est indispensable avant une analyse ?',jsonb_build_array('A) Population et échantillon','B) Moyenne et somme','C) CSV et JSON','D) Python et SQL'),'A','debutant','Raisonnement statistique','La population est la cible, l’échantillon la partie observée.'),(2,'true_false','Une corrélation observée suffit à prouver une causalité.',jsonb_build_array('A) Vrai','B) Faux','C) Toujours en régression','D) Seulement avec pandas'),'B','debutant','Raisonnement statistique','Une association ne prouve pas un lien causal.'),(3,'comprehension','Quel type de variable est un niveau de satisfaction ordonné ?',jsonb_build_array('A) Ordinale','B) Nominale','C) Continue','D) Identifiant'),'A','intermediaire','Raisonnement statistique','Les catégories sont ordonnées sans distance nécessairement constante.'),(4,'mini_challenge','Quelle première étape rend une question métier testable ?',jsonb_build_array('A) Définir population, variable cible et comparaison','B) Choisir un modèle complexe','C) Supprimer les valeurs extrêmes','D) Calculer une p-value'),'A','avance','Raisonnement statistique','Le cadrage précède les calculs.'))
INSERT INTO public.quiz_questions(module_id,order_index,question_type,question,options,answer,difficulty,skill,explanation,is_active,is_final_test)
SELECT target_module.id,s.order_index,s.question_type,s.question,s.options,s.answer,s.difficulty,s.skill,s.explanation,FALSE,FALSE FROM target_module CROSS JOIN seed s
ON CONFLICT(module_id,order_index) DO UPDATE SET question_type=EXCLUDED.question_type,question=EXCLUDED.question,options=EXCLUDED.options,answer=EXCLUDED.answer,difficulty=EXCLUDED.difficulty,skill=EXCLUDED.skill,explanation=EXCLUDED.explanation,is_active=FALSE,is_final_test=FALSE;

WITH target_module AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='statistics-data-science-python' AND m.order_index=1), seed(order_index,question_type,question,options,answer,difficulty,skill,explanation) AS (VALUES (1,'qcm','Quelle mesure résiste mieux aux valeurs extrêmes ?',jsonb_build_array('A) Médiane','B) Moyenne','C) Variance','D) Étendue'),'A','debutant','Statistiques descriptives','La médiane dépend de l’ordre, pas de l’amplitude des extrêmes.'),(2,'true_false','Un écart-type nul signifie que toutes les valeurs sont identiques.',jsonb_build_array('A) Vrai','B) Faux','C) Seulement pour un échantillon','D) Impossible'),'A','debutant','Statistiques descriptives','Une dispersion nulle implique une valeur constante.'),(3,'comprehension','Que mesure l’intervalle interquartile ?',jsonb_build_array('A) La dispersion des 50 % centraux','B) La moyenne des valeurs','C) Le nombre de lignes','D) La causalité'),'A','intermediaire','Statistiques descriptives','IQR = Q3 - Q1.'),(4,'mini_challenge','Pour une distribution très asymétrique, quel résumé est le plus robuste ?',jsonb_build_array('A) Médiane et IQR','B) Moyenne seule','C) Maximum seul','D) Somme et nombre'),'A','avance','Statistiques descriptives','Médiane et IQR résistent mieux aux extrêmes.'))
