WITH target_module AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='statistics-data-science-python' AND m.order_index=2), seed(order_index,question_type,question,options,answer,difficulty,skill,explanation) AS (VALUES (1,'qcm','Quel graphique montre médiane, quartiles et valeurs atypiques ?',jsonb_build_array('A) Boxplot','B) Camembert','C) Carte','D) Table brute'),'A','debutant','Distributions','Le boxplot synthétise position et dispersion.'),(2,'true_false','Une distribution symétrique est nécessairement normale.',jsonb_build_array('A) Vrai','B) Faux','C) Toujours avec n>30','D) Seulement après standardisation'),'B','debutant','Distributions','La symétrie ne suffit pas à caractériser la normalité.'),(3,'comprehension','Que peut révéler un histogramme multimodal ?',jsonb_build_array('A) Plusieurs sous-populations','B) Une causalité certaine','C) Une erreur Python','D) Une moyenne nulle'),'A','intermediaire','Distributions','Plusieurs pics peuvent signaler des groupes distincts.'),(4,'mini_challenge','Pourquoi appliquer parfois log1p à une variable monétaire ?',jsonb_build_array('A) Réduire l’asymétrie tout en gérant zéro','B) Créer des données','C) Supprimer les unités','D) Garantir la causalité'),'A','avance','Distributions','La transformation compresse les grandes valeurs.'))
