WITH target_module AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='statistics-data-science-python' AND m.order_index=3), seed(order_index,question_type,question,options,answer,difficulty,skill,explanation) AS (VALUES (1,'qcm','Quelle notation décrit P(A sachant B) ?',jsonb_build_array('A) P(A|B)','B) P(A+B)','C) P(A-B)','D) P(A*B)'),'A','debutant','Probabilités','La barre verticale représente la condition.'),(2,'true_false','Deux événements indépendants peuvent être mutuellement exclusifs avec probabilités positives.',jsonb_build_array('A) Vrai','B) Faux','C) Toujours','D) Seulement si égaux'),'B','debutant','Probabilités','S’ils sont exclusifs et positifs, observer l’un change la probabilité de l’autre.'),(3,'comprehension','Quelle loi modélise un nombre de succès sur n essais indépendants ?',jsonb_build_array('A) Binomiale','B) Normale','C) Uniforme','D) Exponentielle'),'A','intermediaire','Probabilités','La loi binomiale compte les succès de Bernoulli.'),(4,'mini_challenge','Quelle règle permet d’inverser une probabilité conditionnelle ?',jsonb_build_array('A) Théorème de Bayes','B) Loi des grands nombres','C) ANOVA','D) Bootstrap'),'A','avance','Probabilités','Bayes relie P(A|B) et P(B|A).'))
