WITH target_module AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='statistics-data-science-python' AND m.order_index=4), seed(order_index,question_type,question,options,answer,difficulty,skill,explanation) AS (VALUES (1,'qcm','Que quantifie l’erreur standard ?',jsonb_build_array('A) La variabilité d’un estimateur','B) La dispersion brute seulement','C) Le nombre de colonnes','D) Une erreur de saisie'),'A','debutant','Échantillonnage et bootstrap','Elle mesure la variabilité d’échantillonnage.'),(2,'true_false','Le bootstrap rééchantillonne avec remise.',jsonb_build_array('A) Vrai','B) Faux','C) Jamais','D) Seulement deux fois'),'A','debutant','Échantillonnage et bootstrap','Les réplications bootstrap tirent avec remise.'),(3,'comprehension','Un intervalle de confiance à 95 % signifie-t-il 95 % de probabilité pour ce paramètre fixe ?',jsonb_build_array('A) Non, en interprétation fréquentiste','B) Oui toujours','C) Seulement avec pandas','D) Seulement si n=100'),'A','intermediaire','Échantillonnage et bootstrap','Le niveau concerne la procédure répétée.'),(4,'mini_challenge','Quel biais menace un sondage diffusé seulement aux clients actifs ?',jsonb_build_array('A) Biais de sélection','B) Biais de compilation','C) Biais de syntaxe','D) Biais de tri'),'A','avance','Échantillonnage et bootstrap','Les non-actifs ne peuvent pas être représentés.'))
