WITH target_module AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='statistics-data-science-python' AND m.order_index=5), seed(order_index,question_type,question,options,answer,difficulty,skill,explanation) AS (VALUES (1,'qcm','Que représente la p-value ?',jsonb_build_array('A) La probabilité d’un résultat au moins aussi extrême sous H0','B) La probabilité que H0 soit vraie','C) La taille d’effet','D) La puissance'),'A','debutant','Tests d’hypothèses','La p-value est conditionnelle à H0 et au modèle.'),(2,'true_false','Réduire alpha augmente, toutes choses égales, le risque d’erreur de type II.',jsonb_build_array('A) Vrai','B) Faux','C) Jamais','D) Seulement en ANOVA'),'A','debutant','Tests d’hypothèses','Une règle plus stricte réduit la puissance à taille fixe.'),(3,'comprehension','Que mesure la puissance d’un test ?',jsonb_build_array('A) La probabilité de détecter un effet réel donné','B) La taille de l’échantillon','C) La p-value minimale','D) La variance totale'),'A','intermediaire','Tests d’hypothèses','Puissance = 1 - bêta.'),(4,'mini_challenge','Quelle pratique évite de choisir le test après avoir vu le résultat ?',jsonb_build_array('A) Préspécifier hypothèses et méthode','B) Essayer jusqu’à p<0,05','C) Supprimer les groupes','D) Changer alpha après coup'),'A','avance','Tests d’hypothèses','La préspécification limite le p-hacking.'))
