WITH target_module AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='statistics-data-science-python' AND m.order_index=6), seed(order_index,question_type,question,options,answer,difficulty,skill,explanation) AS (VALUES (1,'qcm','Quelle variante du t-test gère mieux des variances inégales ?',jsonb_build_array('A) Welch','B) Student à variances égales','C) Chi-deux','D) Pearson'),'A','debutant','Comparer des groupes','Welch n’impose pas l’égalité des variances.'),(2,'true_false','Mann-Whitney teste toujours uniquement une différence de médiane.',jsonb_build_array('A) Vrai','B) Faux','C) Seulement si n>30','D) Toujours avec scipy'),'B','debutant','Comparer des groupes','Il porte sur les distributions/rangs ; la lecture médiane exige des conditions.'),(3,'comprehension','Après une ANOVA significative, que faut-il ajouter ?',jsonb_build_array('A) Des comparaisons post-hoc contrôlées','B) Un second histogramme uniquement','C) Une régression logistique','D) Aucune analyse'),'A','intermediaire','Comparer des groupes','Le test global ne localise pas les différences.'),(4,'mini_challenge','Quelle taille d’effet convient à un tableau de contingence ?',jsonb_build_array('A) V de Cramér','B) Cohen d','C) R carré ajusté','D) MAE'),'A','avance','Comparer des groupes','Le V de Cramér quantifie l’association catégorielle.'))
