WITH target_module AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='statistics-data-science-python' AND m.order_index=7), seed(order_index,question_type,question,options,answer,difficulty,skill,explanation) AS (VALUES (1,'qcm','Pearson mesure principalement quelle relation ?',jsonb_build_array('A) Linéaire','B) Nominale','C) Causale','D) Saisonnière'),'A','debutant','Corrélation et régression','Pearson résume une association linéaire.'),(2,'true_false','Spearman travaille sur les rangs.',jsonb_build_array('A) Vrai','B) Faux','C) Seulement les moyennes','D) Seulement les résidus'),'A','debutant','Corrélation et régression','Il mesure une association monotone via les rangs.'),(3,'comprehension','Dans une régression multiple, un coefficient s’interprète comment ?',jsonb_build_array('A) Toutes choses égales par ailleurs','B) Comme une causalité certaine','C) Sans tenir compte des autres variables','D) Comme une corrélation de rang'),'A','intermediaire','Corrélation et régression','Il est conditionnel aux variables incluses.'),(4,'mini_challenge','Quel diagnostic révèle une variance des résidus croissante ?',jsonb_build_array('A) Graphique résidus vs valeurs ajustées','B) Histogramme des identifiants','C) Table des noms','D) Compteur de colonnes'),'A','avance','Corrélation et régression','Une forme en entonnoir suggère l’hétéroscédasticité.'))
