WITH target_module AS (SELECT m.id FROM public.modules m JOIN public.courses c ON c.id=m.course_id WHERE c.slug='statistics-data-science-python' AND m.order_index=11), seed(order_index,question_type,question,options,answer,difficulty,skill,explanation) AS (VALUES (101,'qcm','Quelle mesure robuste résume le centre d’une distribution asymétrique ?',jsonb_build_array('A) Médiane','B) Moyenne','C) Variance','D) Étendue'),'A','intermediaire','synthèse','La bonne réponse est Médiane.'),(102,'qcm','Quelle méthode estime l’incertitude par rééchantillonnage avec remise ?',jsonb_build_array('A) Bootstrap','B) ANOVA','C) KMeans','D) PCA'),'A','intermediaire','synthèse','La bonne réponse est Bootstrap.'),(103,'qcm','Que complète idéalement une p-value ?',jsonb_build_array('A) Une taille d’effet et un intervalle de confiance','B) Un logo','C) Une clé primaire','D) Un tri alphabétique'),'A','intermediaire','synthèse','La bonne réponse est Une taille d’effet et un intervalle de confiance.'),(104,'qcm','Quel test compare plusieurs moyennes ?',jsonb_build_array('A) ANOVA','B) Pearson','C) KMeans','D) MAE'),'A','intermediaire','synthèse','La bonne réponse est ANOVA.'),(105,'qcm','Quelle corrélation convient à une relation monotone sur rangs ?',jsonb_build_array('A) Spearman','B) Pearson uniquement','C) Chi-deux','D) Cohen d'),'A','intermediaire','synthèse','La bonne réponse est Spearman.'),(106,'qcm','Pourquoi standardiser avant KMeans ?',jsonb_build_array('A) Mettre les variables sur des échelles comparables','B) Choisir automatiquement K','C) Créer la cible','D) Supprimer les clients'),'A','intermediaire','synthèse','La bonne réponse est Mettre les variables sur des échelles comparables.'),(107,'qcm','Quel découpage convient aux séries temporelles ?',jsonb_build_array('A) Passé pour train, futur pour test','B) Aléatoire sans date','C) Futur pour train','D) Aucun test'),'A','intermediaire','synthèse','La bonne réponse est Passé pour train, futur pour test.'),(108,'qcm','Quelle métrique pénalise davantage les grosses erreurs ?',jsonb_build_array('A) RMSE','B) MAE','C) Médiane','D) Silhouette'),'A','intermediaire','synthèse','La bonne réponse est RMSE.'),(109,'qcm','Quel signe classique indique le surapprentissage ?',jsonb_build_array('A) Grand écart train-validation','B) Deux colonnes','C) Une moyenne nulle','D) Un index datetime'),'A','intermediaire','synthèse','La bonne réponse est Grand écart train-validation.'),(110,'qcm','Une importance de variable prouve-t-elle la causalité ?',jsonb_build_array('A) Non','B) Oui toujours','C) Seulement avec forêt','D) Seulement avec régression'),'A','intermediaire','synthèse','La bonne réponse est Non.'),(111,'qcm','Que faut-il fixer pour rendre une analyse reproductible ?',jsonb_build_array('A) Dépendances, graines, données et ordre d’exécution','B) Couleur du thème seulement','C) Taille d’écran','D) Nom du dossier seul'),'A','intermediaire','synthèse','La bonne réponse est Dépendances, graines, données et ordre d’exécution.'),(112,'qcm','Quel principe guide une recommandation responsable ?',jsonb_build_array('A) Proportionner la décision aux preuves et documenter les risques','B) Masquer l’incertitude','C) Collecter toutes les données','D) Automatiser sans contrôle'),'A','intermediaire','synthèse','La bonne réponse est Proportionner la décision aux preuves et documenter les risques.'))
INSERT INTO public.quiz_questions(module_id,order_index,question_type,question,options,answer,difficulty,skill,explanation,is_active,is_final_test)
