INSERT INTO public.course_projects(course_id,slug,title,summary,brief_md,corpus_policy_md,starter_assets,minimum_version,advanced_version,functional_criteria,technical_criteria,rubric,reference_solution_md,is_published)
SELECT c.id,'prevision-ventes-segmentation-clients-python','Prévision des ventes et segmentation des clients avec Python','Construire une étude Data Science reproductible combinant prévision temporelle, segmentation client et recommandations métier.',
'# Brief

Vous êtes Data Scientist pour une entreprise de distribution. À partir des transactions clients et des ventes datées, vous devez contrôler la qualité des données, explorer les distributions, comparer des groupes, segmenter les clients et prévoir les ventes. La restitution doit expliquer les choix statistiques, quantifier l’incertitude et proposer des actions responsables.

## Livrables
- notebook professionnel réexécutable ;
- rapport de qualité des données ;
- analyse descriptive et tests statistiques ;
- segmentation KMeans profilée ;
- prévision de ventes avec validation temporelle ;
- comparaison à des baselines ;
- synthèse métier avec limites, éthique et recommandations.',
'# Politique des données

Utiliser uniquement le corpus pédagogique fourni. Ne pas introduire de données personnelles externes. Documenter les transformations, exclusions et hypothèses. Toute recommandation doit rester proportionnée aux preuves.',
'[{"path":"/resources/statistics-data-science/transactions_clients.csv","purpose":"Transactions et comportement client"},{"path":"/resources/statistics-data-science/ventes_journalieres.csv","purpose":"Historique des ventes"},{"path":"/resources/statistics-data-science/dictionnaire_donnees.md","purpose":"Définition des variables"},{"path":"/resources/statistics-data-science/starter_notebook.ipynb","purpose":"Structure de départ"}]'::jsonb,
'["Nettoyer et documenter les données","Produire une analyse descriptive complète","Comparer au moins deux groupes avec taille d’effet","Créer 3 à 6 segments clients interprétables","Construire une baseline de prévision et un modèle évalué","Présenter cinq recommandations et leurs limites"]'::jsonb,
'["Comparer plusieurs méthodes de clustering","Tester la stabilité des segments","Construire une validation walk-forward multi-horizon","Ajouter des intervalles de prévision","Créer un pipeline reproductible et automatisé"]'::jsonb,
'["Les données sont contrôlées et traçables","Les tests répondent à des questions métier","Les segments sont stables et actionnables","La prévision est comparée à une baseline","Les recommandations reposent sur les résultats"]'::jsonb,
'["Notebook exécutable depuis un environnement propre","Transformations sans fuite de données","Random states fixés","Validation temporelle correcte","Métriques justifiées","Code factorisé et documenté","Limites et risques éthiques explicités"]'::jsonb,
'[{"criterion":"Qualité et préparation des données","points":8},{"criterion":"Analyse statistique","points":10},{"criterion":"Segmentation client","points":12},{"criterion":"Prévision des ventes","points":12},{"criterion":"Évaluation et robustesse","points":8},{"criterion":"Communication, éthique et recommandations","points":10}]'::jsonb,
'# Solution de référence

La solution attendue construit une table client au grain correct, standardise les variables dans un pipeline, compare plusieurs valeurs de K avec inertie, silhouette et stabilité, profile les segments sur les valeurs originales, crée des baselines naïve et saisonnière, évalue une prévision avec séparation temporelle et walk-forward, puis livre un notebook reproductible et une restitution métier honnête.',FALSE FROM c
