(6,'comparer-groupes','Comparer les groupes','Tester des différences et quantifier leur importance.','["Tests statistiques","Tailles d’effet","Intervalles"]'::jsonb,'["Hypothèses vérifiées","Test adapté","Conclusion métier prudente"]'::jsonb,2),
(8,'segmenter-clients','Segmenter les clients','Préparer, standardiser, entraîner KMeans et profiler les groupes.','["Pipeline de segmentation","Profils de segments"]'::jsonb,'["K justifié","Stabilité examinée","Segments actionnables"]'::jsonb,3),
(9,'prevoir-ventes','Prévoir les ventes','Construire baselines, modèle et validation temporelle.','["Prévisions","Comparatif de métriques","Graphiques temporels"]'::jsonb,'["Aucune fuite temporelle","Baseline battue ou limites expliquées","Horizon défini"]'::jsonb,4),
(10,'evaluer-robustesse','Évaluer la robustesse','Contrôler généralisation, erreurs et limites.','["Diagnostic train/validation","Analyse d’erreurs","Limites"]'::jsonb,'["Métriques justifiées","Sous-groupes contrôlés","Surapprentissage discuté"]'::jsonb,5),
