INSERT INTO public.course_project_milestones(project_id,module_id,slug,title,description,deliverables,acceptance_criteria,order_index,is_published)
SELECT p.project_id,m.id,s.slug,s.title,s.description,s.deliverables,s.acceptance,s.ord,FALSE FROM p JOIN public.modules m ON m.course_id=p.course_id JOIN seed s ON s.module_order=m.order_index
ON CONFLICT(project_id,slug) DO UPDATE SET module_id=EXCLUDED.module_id,title=EXCLUDED.title,description=EXCLUDED.description,deliverables=EXCLUDED.deliverables,acceptance_criteria=EXCLUDED.acceptance_criteria,order_index=EXCLUDED.order_index,is_published=FALSE;

DO $$
DECLARE quiz_count INT; final_count INT; project_count INT; milestone_count INT; rubric_total INT; active_count INT; published_count INT;
BEGIN
 SELECT COUNT(*) FILTER (WHERE q.is_final_test=FALSE),COUNT(*) FILTER (WHERE q.is_final_test=TRUE),COUNT(*) FILTER (WHERE q.is_active) INTO quiz_count,final_count,active_count FROM public.quiz_questions q JOIN public.modules m ON m.id=q.module_id JOIN public.courses c ON c.id=m.course_id WHERE c.slug='statistics-data-science-python';
 SELECT COUNT(*),COUNT(*) FILTER (WHERE cp.is_published) INTO project_count,published_count FROM public.course_projects cp JOIN public.courses c ON c.id=cp.course_id WHERE c.slug='statistics-data-science-python';
 SELECT COUNT(*) INTO milestone_count FROM public.course_project_milestones pm JOIN public.course_projects cp ON cp.id=pm.project_id JOIN public.courses c ON c.id=cp.course_id WHERE c.slug='statistics-data-science-python';
 SELECT COALESCE(SUM((item->>'points')::INT),0) INTO rubric_total FROM public.course_projects cp JOIN public.courses c ON c.id=cp.course_id,LATERAL jsonb_array_elements(cp.rubric) item WHERE c.slug='statistics-data-science-python';
 IF quiz_count<>48 OR final_count<>12 OR project_count<>1 OR milestone_count<>7 OR rubric_total<>60 OR active_count<>0 OR published_count<>0 THEN RAISE EXCEPTION 'Chantier 4 Statistiques incomplet: quiz %, final %, projets %, jalons %, barème %, actifs %, publiés %',quiz_count,final_count,project_count,milestone_count,rubric_total,active_count,published_count; END IF;
END $$;
